import pandas as pd
import json
import stan

stan_code = """
functions {
  matrix cov_ard_sqexp(matrix X, vector rho, real alpha, real jitter) {
    int N = rows(X);
    int D = cols(X);
    matrix[N, N] K;

    for (i in 1:N) {
      K[i, i] = square(alpha) + jitter;
      for (j in (i + 1):N) {
        real s = 0;
        for (d in 1:D) {
          real t = (X[i, d] - X[j, d]) / rho[d];
          s += t * t;
        }
        K[i, j] = square(alpha) * exp(-0.5 * s);
        K[j, i] = K[i, j];
      }
    }
    return K;
  }

  matrix cross_cov_ard(matrix X, matrix X_new, vector rho, real alpha) {
    int N = rows(X);
    int M = rows(X_new);
    int D = cols(X); // == cols(X_new)
    matrix[N, M] Kx;
    for (i in 1:N) {
      for (j in 1:M) {
        real s = 0;
        for (d in 1:D) {
          real t = (X[i, d] - X_new[j, d]) / rho[d];
          s += t * t;
        }
        Kx[i, j] = square(alpha) * exp(-0.5 * s);
      }
    }
    return Kx;
  }
}

data {
  int<lower=1> N;
  int<lower=1> D;
  matrix[N, D] X;
  int<lower=1> P;
  matrix[N, P] H;
  vector[N] y;
  real<lower=0> jitter;

  int<lower=0> N_new;
  matrix[N_new, D] X_new;
  matrix[N_new, P] H_new;
}

parameters {
  vector[P] beta;
  real<lower=0> alpha;
  vector<lower=0>[D] rho;
  real<lower=0> sigma;
}

transformed parameters {
  vector[N] mu = H * beta;
  matrix[N, N] K = cov_ard_sqexp(X, rho, alpha, jitter)
                   + diag_matrix(rep_vector(square(sigma), N));
  matrix[N, N] L_K = cholesky_decompose(K);
}

model {
  beta  ~ normal(0, 1);
  alpha ~ normal(0, 1.5);
  rho   ~ lognormal(0, 1);
  sigma ~ normal(0, 0.5);
  y ~ multi_normal_cholesky(mu, L_K);
}

generated quantities {
  vector[N_new] y_new;
  if (N_new > 0) {
    matrix[N, N_new] K_x_xnew = cross_cov_ard(X, X_new, rho, alpha);
    matrix[N_new, N_new] K_new = cov_ard_sqexp(X_new, rho, alpha, jitter);
    vector[N] resid = y - (H * beta);

    vector[N] alpha_vec = mdivide_left_tri_low(L_K, resid);
    alpha_vec = mdivide_left_tri_low(L_K', alpha_vec);

    vector[N_new] f_mean = (K_x_xnew' * alpha_vec);
    matrix[N, N_new] v = mdivide_left_tri_low(L_K, K_x_xnew);
    vector[N_new] f_var = to_vector(diagonal(K_new)) - to_vector(columns_dot_self(v));
    for (m in 1:N_new) {
      real m_mean = (H_new[m] * beta) + f_mean[m];
      real m_sd   = sqrt(f_var[m] + square(sigma));
      y_new[m] = normal_rng(m_mean, m_sd);
    }
  }
}
"""

# Load data
with open("/app/meta_public.json", "r") as f:
    meta_pub = json.load(f)

train_X_df = pd.read_csv("/app/train_X.csv")
test_X_df = pd.read_csv("/app/test_X.csv")
train_y_df = pd.read_csv("/app/train_y.csv")

train_X = train_X_df.values
test_X = test_X_df.values
train_y = train_y_df["y"].values

P = int(meta_pub["P"])
jitter = float(meta_pub["jitter"])

N, D = train_X.shape
N_new = test_X.shape[0]

# Build H matrix: cbind(1, train_X[,1], train_X[,2])
H = np.column_stack([np.ones(N), train_X[:, 0], train_X[:, 1]])

if N_new > 0:
    H_new = np.column_stack([np.ones(N_new), test_X[:, 0], test_X[:, 1]])
else:
    H_new = np.zeros((0, P))

data_dict = {
    "N": N,
    "D": D,
    "X": train_X.tolist(),
    "P": P,
    "H": H.tolist(),
    "y": train_y.tolist(),
    "jitter": jitter,
    "N_new": N_new,
    "X_new": test_X.tolist() if N_new > 0 else [],
    "H_new": H_new.tolist() if N_new > 0 else [],
}

# Build the model with random_seed=1
print("Building Stan model...")
model = stan.build(stan_code, data=data_dict, random_seed=1)

# Sample: chains=4, iter=2000, warmup=1000, thin=2, seed=1
# In PyStan 3, sample() returns draws directly.
# We need to match RStan's behavior: 4 chains, 2000 iterations, 1000 warmup, thin=2
# This gives (2000-1000)/2 = 500 samples per chain, total 2000 samples
print("Sampling...")
posterior = model.sample(
    num_chains=4,
    num_samples=2000,
    warmup_samples=1000,
    thin=2,
    seed=1,
    init_r=0.1,
    adapt_delta=0.93,
    max_treedepth=14,
)

# Extract posterior samples
alpha_samples = posterior["alpha"]  # shape: (num_chains, num_samples)
sigma_samples = posterior["sigma"]
rho_samples = posterior["rho"]   # shape: (num_chains, num_samples, D)
beta_samples = posterior["beta"]  # shape: (num_chains, num_samples, P)

# Flatten all chains and samples
alpha_flat = alpha_samples.flatten()
sigma_flat = sigma_samples.flatten()
rho_flat = rho_samples.reshape(-1, D)
beta_flat = beta_samples.reshape(-1, P)

# Compute posterior means
alpha_est = float(np.mean(alpha_flat))
sigma_est = float(np.mean(sigma_flat))
rho_est = np.mean(rho_flat, axis=0)
beta_est = np.mean(beta_flat, axis=0)

print(f"Posterior means:")
print(f"alpha: {alpha_est}")
print(f"sigma: {sigma_est}")
print(f"rho:  {rho_est}")
print(f"beta: {beta_est}")

# Save results
np.savetxt("/app/alpha_est.csv", [alpha_est], delimiter=",")
np.savetxt("/app/sigma_est.csv", [sigma_est], delimiter=",")
np.savetxt("/app/rho_est.csv", rho_est, delimiter=",")
np.savetxt("/app/beta_est.csv", beta_est, delimiter=",")

print("Results saved to /app/alpha_est.csv, /app/sigma_est.csv, /app/rho_est.csv, /app/beta_est.csv")
"}

